import{_ as t,c as r,o,a5 as i,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.7: Interactive Q&A + Mobile Optimization","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.7.md","filePath":"en/changelog/v1.1.7.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.7.md"};function l(s,a,d,c,h,p){return o(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="v1-1-7-interactive-q-a-mobile-optimization" tabindex="-1">v1.1.7: Interactive Q&amp;A + Mobile Optimization <a class="header-anchor" href="#v1-1-7-interactive-q-a-mobile-optimization" aria-label="Permalink to “v1.1.7: Interactive Q&amp;A + Mobile Optimization”">​</a></h1><p><strong>Release Date</strong>: January 8, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update adds an <strong>interactive Q&amp;A tool</strong> that lets AI actively ask you questions to gather information, while optimizing the narrow screen/mobile experience.</p><hr><h2 id="new-feature-interactive-q-a-tool" tabindex="-1">New Feature: Interactive Q&amp;A Tool <a class="header-anchor" href="#new-feature-interactive-q-a-tool" aria-label="Permalink to “New Feature: Interactive Q&amp;A Tool”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>AI can now <strong>actively ask you questions</strong> to collect your preferences and requirements, instead of guessing what you want.</p><h3 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to “Use Cases”">​</a></h3><p>For example, when you say &quot;help me create a project&quot;, AI might ask:</p><ul><li>Which framework to use? (React / Vue / Svelte)</li><li>Need TypeScript? (Yes / No)</li><li>Which tools to configure? (ESLint / Prettier / Testing framework)</li></ul><p>After you choose, AI executes according to your selections, avoiding unexpected decisions.</p><h3 id="why-is-this-useful" tabindex="-1">Why Is This Useful? <a class="header-anchor" href="#why-is-this-useful" aria-label="Permalink to “Why Is This Useful?”">​</a></h3><p>Previously, when AI encountered uncertain situations, it would either guess (possibly wrong) or stop to ask in text (inconvenient to choose). Now with a structured Q&amp;A interface, interaction is clearer.</p><hr><h2 id="improvement-narrow-screen-mobile-experience" tabindex="-1">Improvement: Narrow Screen/Mobile Experience <a class="header-anchor" href="#improvement-narrow-screen-mobile-experience" aria-label="Permalink to “Improvement: Narrow Screen/Mobile Experience”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>On narrow screens (phones, small windows):</p><ul><li>Sidebar changed to <strong>overlay popup</strong>, no longer squeezing main content</li><li>Auto-hide top and bottom bars for more space</li><li>Autocomplete height adapts to screen</li></ul><h3 id="effect" tabindex="-1">Effect <a class="header-anchor" href="#effect" aria-label="Permalink to “Effect”">​</a></h3><p>Using OpenCode on phones or small windows is now more comfortable.</p><hr><h2 id="improvement-long-command-output-collapsible" tabindex="-1">Improvement: Long Command Output Collapsible <a class="header-anchor" href="#improvement-long-command-output-collapsible" aria-label="Permalink to “Improvement: Long Command Output Collapsible”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Executing a command with long output (like <code>npm install</code>) would fill the screen, making it hard to see other content.</p><h3 id="current-behavior" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior" aria-label="Permalink to “Current Behavior”">​</a></h3><p>Long command output is now <strong>collapsed by default</strong>, click to expand and view full content.</p><hr><h2 id="improvement-configuration-priority-fix" tabindex="-1">Improvement: Configuration Priority Fix <a class="header-anchor" href="#improvement-configuration-priority-fix" aria-label="Permalink to “Improvement: Configuration Priority Fix”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Local project configuration (<code>.opencode/settings.json</code>) sometimes couldn&#39;t override global configuration.</p><h3 id="current-behavior-1" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior-1" aria-label="Permalink to “Current Behavior”">​</a></h3><p>Configuration priority now works correctly: <strong>Project config &gt; Global config &gt; Remote config</strong>.</p><hr><h2 id="desktop-app-external-links-open-in-browser" tabindex="-1">Desktop App: External Links Open in Browser <a class="header-anchor" href="#desktop-app-external-links-open-in-browser" aria-label="Permalink to “Desktop App: External Links Open in Browser”">​</a></h2><h3 id="previous-issue-2" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-2" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Clicking links in conversations would open inside the desktop app, poor experience.</p><h3 id="current-behavior-2" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior-2" aria-label="Permalink to “Current Behavior”">​</a></h3><p>External links now open in your <strong>default browser</strong>.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Frequently use on phone/small screen</td><td>✅ Upgrade</td></tr><tr><td>Want smarter AI questioning</td><td>✅ Upgrade</td></tr><tr><td>Configuration override not working</td><td>✅ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',44),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Add interactive Q&amp;A tool for collecting user preferences and clarifying instructions</li><li>Add kind, title, rawInput fields to ACP tool_call_update event (@noamzbr)</li><li>Add help text to debug command (@assagman)</li><li>Allow disabling .claude prompts and skills loading (@freespace8)</li><li>Fix transform options conflict when generating titles</li><li>Write long tool output to files</li><li>Simplify Task tool subagent filtering logic (@malhashemi)</li><li>Improve title generation, avoid duplicate &quot;Analyzing...&quot; prefix</li><li>Fix using correct authorization server URL for MCP OAuth discovery (@rscarvalho)</li><li>Fix configuration priority, local config correctly overrides remote config (@elithrar)</li><li>Update Homebrew formula</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Restore showDetails check removed in permission refactoring (@ryanwyler)</li><li>Properly restore terminal state on fatal error exit (@itsrainingmani)</li><li>Hide top and bottom bars when sidebar visible, optimize responsive layout</li><li>Simplify session settings management (@maxstevens-nl)</li><li>Use overlay sidebar on narrow screens</li><li>Long command output collapsible and expandable</li><li>Remove username display toggle, simplify user message metadata</li><li>Improve Q&amp;A option indentation and label clarity</li><li>Correctly insert message text to input box when forking conversation (@ariane-emory)</li><li>Use selected foreground color for permission selection text (@ariane-emory)</li><li>Limit autocomplete height within available screen space (@Raviguntakala)</li><li>Add selectedListItemText to orange theme to improve button text visibility (@ThanhNguyxn)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Show custom models without valid release_date (@zerone0x)</li><li>Open external links in default browser (@athal7)</li></ul><h3 id="community-contributors" tabindex="-1">Community Contributors <a class="header-anchor" href="#community-contributors" aria-label="Permalink to “Community Contributors”">​</a></h3><p>Thanks to 15 community contributors!</p></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=t(n,[["render",l]]);export{m as __pageData,g as default};
